# -*- coding: UTF-8 -*-\n\"\"\"\nDebug Route for Parameter Analysis\n\"\"\"\n\nfrom pyrevit import routes\nimport Autodesk.Revit.DB as DB\nfrom . import logger\nfrom .utils import safe_string\n\n\ndef register_debug_routes(api):\n    \"\"\"Register debug routes\"\"\"\n    \n    @api.route('/debug_element_parameters/<category>', methods=[\"GET\"])\n    def debug_element_parameters(doc, category):\n        \"\"\"Debug: Show all parameters of first element in category\"\"\"\n        try:\n            # Import fuzzy matcher\n            import sys\n            import os\n            lib_path = os.path.join(os.path.dirname(os.path.dirname(__file__)), 'lib')\n            if lib_path not in sys.path:\n                sys.path.append(lib_path)\n            \n            from fuzzy_category_matcher import resolve_category\n            \n            # Resolve category\n            canonical_label, built_in_category, confidence = resolve_category(category)\n            \n            if not built_in_category:\n                return routes.make_response(data={\"error\": \"Category not found\"}, status=400)\n            \n            # Get first element in category\n            elements = DB.FilteredElementCollector(doc).OfCategory(built_in_category).WhereElementIsNotElementType()\n            first_element = None\n            \n            for element in elements:\n                first_element = element\n                break\n            \n            if not first_element:\n                return routes.make_response(data={\"error\": \"No elements in category\"}, status=400)\n            \n            # Get ALL parameters\n            parameters = []\n            for param in first_element.Parameters:\n                param_name = safe_string(param.Definition.Name)\n                param_type = safe_string(str(param.StorageType))\n                has_value = param.HasValue\n                value = None\n                \n                if has_value:\n                    if param.StorageType == DB.StorageType.String:\n                        value = safe_string(param.AsString())\n                    elif param.StorageType == DB.StorageType.ElementId:\n                        value = param.AsElementId().IntegerValue\n                    elif param.StorageType == DB.StorageType.Double:\n                        value = param.AsDouble()\n                    elif param.StorageType == DB.StorageType.Integer:\n                        value = param.AsInteger()\n                \n                parameters.append({\n                    \"name\": param_name,\n                    \"type\": param_type,\n                    \"has_value\": has_value,\n                    \"value\": value\n                })\n            \n            # Test specific lookups\n            level_param = first_element.LookupParameter(\"Level\")\n            base_constraint_param = first_element.LookupParameter(\"Base Constraint\")\n            \n            return routes.make_response(data={\n                \"status\": \"success\",\n                \"category\": canonical_label,\n                \"element_id\": first_element.Id.IntegerValue,\n                \"element_name\": safe_string(first_element.Name),\n                \"total_parameters\": len(parameters),\n                \"parameters\": parameters,\n                \"level_lookup_result\": level_param is not None,\n                \"base_constraint_lookup_result\": base_constraint_param is not None\n            })\n            \n        except Exception as e:\n            logger.error(\"Debug error: {}\".format(safe_string(str(e))))\n            return routes.make_response(data={\"error\": safe_string(str(e))}, status=500)\n